library ieee;
use ieee.std_logic_1164.all;

entity comparator_64bit is
  port (
    data_in_a : in std_logic_vector(63 downto 0);
    data_in_b : in std_logic_vector(63 downto 0);
    equal_out : out std_logic
  );
end entity comparator_64bit;

architecture rtl of comparator_64bit is
begin
  process(data_in_a)
  begin
    if (data_in_a = data_in_b) then
      equal_out <= '1';
    else
      equal_out <= '0';
    end if;
  end process;
end architecture rtl;

